204: func validateBackendBatchOptions(pluginName string, options AuditBatchOptions) error {
205: 	if err := validateBackendMode(pluginName, options.Mode); err != nil {
206: 		return err
207: 	}
208: 	if options.Mode != ModeBatch {
209: 		// Don't validate the unused options.
210: 		return nil
211: 	}
212: 	config := options.BatchConfig
213: 	if config.BufferSize <= 0 {
214: 		return fmt.Errorf("invalid audit batch %s buffer size %v, must be a positive number", pluginName, config.BufferSize)
215: 	}
216: 	if config.MaxBatchSize <= 0 {
217: 		return fmt.Errorf("invalid audit batch %s max batch size %v, must be a positive number", pluginName, config.MaxBatchSize)
218: 	}
219: 	if config.ThrottleEnable {
220: 		if config.ThrottleQPS <= 0 {
221: 			return fmt.Errorf("invalid audit batch %s throttle QPS %v, must be a positive number", pluginName, config.ThrottleQPS)
222: 		}
223: 		if config.ThrottleBurst <= 0 {
224: 			return fmt.Errorf("invalid audit batch %s throttle burst %v, must be a positive number", pluginName, config.ThrottleBurst)
225: 		}
226: 	}
227: 	return nil
228: }
