457: func (o *AuditLogOptions) Validate() []error {
458: 	// Check whether the log backend is enabled based on the options.
459: 	if !o.enabled() {
460: 		return nil
461: 	}
462: 
463: 	var allErrors []error
464: 
465: 	if err := validateBackendBatchOptions(pluginlog.PluginName, o.BatchOptions); err != nil {
466: 		allErrors = append(allErrors, err)
467: 	}
468: 	if err := o.TruncateOptions.Validate(pluginlog.PluginName); err != nil {
469: 		allErrors = append(allErrors, err)
470: 	}
471: 
472: 	if err := validateGroupVersionString(o.GroupVersionString); err != nil {
473: 		allErrors = append(allErrors, err)
474: 	}
475: 
476: 	// Check log format
477: 	if !sets.NewString(pluginlog.AllowedFormats...).Has(o.Format) {
478: 		allErrors = append(allErrors, fmt.Errorf("invalid audit log format %s, allowed formats are %q", o.Format, strings.Join(pluginlog.AllowedFormats, ",")))
479: 	}
480: 
481: 	// Check validities of MaxAge, MaxBackups and MaxSize of log options, if file log backend is enabled.
482: 	if o.MaxAge < 0 {
483: 		allErrors = append(allErrors, fmt.Errorf("--audit-log-maxage %v can't be a negative number", o.MaxAge))
484: 	}
485: 	if o.MaxBackups < 0 {
486: 		allErrors = append(allErrors, fmt.Errorf("--audit-log-maxbackup %v can't be a negative number", o.MaxBackups))
487: 	}
488: 	if o.MaxSize < 0 {
489: 		allErrors = append(allErrors, fmt.Errorf("--audit-log-maxsize %v can't be a negative number", o.MaxSize))
490: 	}
491: 
492: 	return allErrors
493: }
