500: func (o *AuditLogOptions) getWriter() (io.Writer, error) {
501: 	if !o.enabled() {
502: 		return nil, nil
503: 	}
504: 
505: 	if o.Path == "-" {
506: 		return os.Stdout, nil
507: 	}
508: 
509: 	if err := o.ensureLogFile(); err != nil {
510: 		return nil, fmt.Errorf("ensureLogFile: %w", err)
511: 	}
512: 
513: 	if o.MaxSize == 0 {
514: 		return os.OpenFile(o.Path, os.O_APPEND|os.O_WRONLY, 0644)
515: 	}
516: 
517: 	return &lumberjack.Logger{
518: 		Filename:   o.Path,
519: 		MaxAge:     o.MaxAge,
520: 		MaxBackups: o.MaxBackups,
521: 		MaxSize:    o.MaxSize,
522: 		Compress:   o.Compress,
523: 	}, nil
524: }
