526: func (o *AuditLogOptions) ensureLogFile() error {
527: 	if err := os.MkdirAll(filepath.Dir(o.Path), 0700); err != nil {
528: 		return err
529: 	}
530: 	mode := os.FileMode(0600)
531: 	f, err := os.OpenFile(o.Path, os.O_CREATE|os.O_APPEND|os.O_RDWR, mode)
532: 	if err != nil {
533: 		return err
534: 	}
535: 	return f.Close()
536: }
